	"strconv"
	"strings"

	"github.com/gorilla/mux"
	"github.com/rs/cors"
	"gorm.io/gorm"
)

// CORS helpers configured via environment variables

func getListEnv(key, def string) []string { // default empty - allows any string, splits on comma
	val := strings.TrimSpace(os.Getenv(key))
	if val == "" {
		val = def
	}
	if val == "" {
		return nil
	}
	parts := strings.Split(val, ",")
	out := make([]string, 0, len(parts))
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

func getBoolEnv(key string, def bool) bool { // default false - allows any string to be false except specific true values
	v := strings.TrimSpace(strings.ToLower(os.Getenv(key)))
	if v == "" {
		return def
	}
	return v == "1" || v == "true" || v == "yes" || v == "on"
}

func getIntEnv(key string, def int) int { // default 0 - allows any string to be int, otherwise default
	v := strings.TrimSpace(os.Getenv(key))
	if v == "" {
		return def
	}
	if n, err := strconv.Atoi(v); err == nil {
		return n
	}
	return def
}

func buildCORSFromEnv() *cors.Cors {
	if !getBoolEnv("CORS_ENABLED", true) {
		return nil
	}
	origins := getListEnv("CORS_ALLOW_ORIGINS", "*")
	methods := getListEnv("CORS_ALLOW_METHODS", "GET,POST,PUT,PATCH,DELETE,OPTIONS")
	headers := getListEnv("CORS_ALLOW_HEADERS", "Content-Type,Authorization")
	expose := getListEnv("CORS_EXPOSE_HEADERS", "")
	allowCreds := getBoolEnv("CORS_ALLOW_CREDENTIALS", false)
	maxAge := getIntEnv("CORS_MAX_AGE", 600)

	return cors.New(cors.Options{
		AllowedOrigins:   origins,
		AllowedMethods:   methods,
		AllowedHeaders:   headers,
		ExposedHeaders:   expose,
		AllowCredentials: allowCreds,
		MaxAge:           maxAge,
	})
}

func Start(openAPISpec []byte, swaggerUIFS embed.FS, db *gorm.DB) {
	// Initialize security service
	securityService := security.NewSecurityService()

	// CORS handler (configurable via env)
	c := buildCORSFromEnv()

	// Initialize mux router
	router := mux.NewRouter()

	// Health endpoint
	router.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "text/plain; charset=utf-8")
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte("ok"))
	}).Methods("GET")

	// OpenAPI spec endpoint
	router.HandleFunc("/openapi.yaml", func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/yaml; charset=utf-8")
		_, _ = w.Write(openAPISpec)
	}).Methods("GET")

	// Swagger UI endpoints
	// Redirect /swagger -> /swagger/
	router.HandleFunc("/swagger", func(w http.ResponseWriter, r *http.Request) {
		http.Redirect(w, r, "/swagger/", http.StatusMovedPermanently)
	})
	// File server rooted at swagger-ui/
	uiFS, err := fs.Sub(swaggerUIFS, "swagger-ui")
	if err != nil {
		log.Fatalf("failed to set up swagger-ui FS: %v", err)
	}
	swaggerHandler := http.FileServer(http.FS(uiFS))
	router.PathPrefix("/swagger/").Handler(http.StripPrefix("/swagger/", swaggerHandler))

	// Initialize domain services
	configService, err := configsvc.NewService(configsvc.LoaderFunc(setup.LoadEconomicsConfig))
	if err != nil {
		log.Fatalf("config init: %v", err)
	}

	container := app.BuildApplicationWithConfigService(db, configService)
	econConfig := configService.Current()
	marketsService := container.GetMarketsService()
	usersService := container.GetUsersService()
	analyticsService := container.GetAnalyticsService()
	authService := container.GetAuthService()

	// Create Handler instances
	marketsHandler := marketshandlers.NewHandler(marketsService, authService)

	// Define endpoint handlers using Gorilla Mux router
	// This defines all functions starting with /api/

	// Apply security middleware to all routes
	securityMiddleware := securityService.SecurityMiddleware()
	loginSecurityMiddleware := securityService.LoginSecurityMiddleware()

	router.HandleFunc("/v0/home", handlers.HomeHandler).Methods("GET")
	router.Handle("/v0/login", loginSecurityMiddleware(authsvc.LoginHandler(db))).Methods("POST")

	// application setup and stats information
	router.Handle("/v0/setup", securityMiddleware(http.HandlerFunc(setuphandlers.GetSetupHandler(container.GetConfigService())))).Methods("GET")
	router.Handle("/v0/setup/frontend", securityMiddleware(http.HandlerFunc(setuphandlers.GetFrontendSetupHandler(container.GetConfigService())))).Methods("GET")
	router.Handle("/v0/stats", securityMiddleware(statshandlers.StatsHandler(db, container.GetConfigService()))).Methods("GET")
	router.Handle("/v0/system/metrics", securityMiddleware(metricshandlers.GetSystemMetricsHandler(analyticsService))).Methods("GET")
	router.Handle("/v0/global/leaderboard", securityMiddleware(metricshandlers.GetGlobalLeaderboardHandler(analyticsService))).Methods("GET")

	// Markets routes - using new Handler instance
	router.Handle("/v0/markets", securityMiddleware(http.HandlerFunc(marketsHandler.ListMarkets))).Methods("GET")
	router.Handle("/v0/markets", securityMiddleware(http.HandlerFunc(marketsHandler.CreateMarket))).Methods("POST")
	router.Handle("/v0/markets/search", securityMiddleware(http.HandlerFunc(marketsHandler.SearchMarkets))).Methods("GET")
	router.Handle("/v0/markets/status/{status}", securityMiddleware(http.HandlerFunc(marketsHandler.ListByStatus))).Methods("GET")
	router.Handle("/v0/markets/status", securityMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		rWithStatus := mux.SetURLVars(r, map[string]string{"status": "all"})
		marketsHandler.ListByStatus(w, rWithStatus)
	}))).Methods("GET")
	router.Handle("/v0/markets/{id}", securityMiddleware(http.HandlerFunc(marketsHandler.GetDetails))).Methods("GET")
	router.Handle("/v0/markets/{id}/resolve", securityMiddleware(http.HandlerFunc(marketsHandler.ResolveMarket))).Methods("POST")
	router.Handle("/v0/markets/{id}/leaderboard", securityMiddleware(http.HandlerFunc(marketsHandler.MarketLeaderboard))).Methods("GET")
	router.Handle("/v0/markets/{id}/projection", securityMiddleware(http.HandlerFunc(marketsHandler.ProjectProbability))).Methods("GET")

	// Legacy routes for backward compatibility — rewrite to new handler with status query
	router.Handle("/v0/markets/active", securityMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		q := r.URL.Query()
		q.Set("status", "active")
		r.URL.RawQuery = q.Encode()
		marketsHandler.ListMarkets(w, r)
	}))).Methods("GET")
	router.Handle("/v0/markets/closed", securityMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		q := r.URL.Query()
		q.Set("status", "closed")
		r.URL.RawQuery = q.Encode()
		marketsHandler.ListMarkets(w, r)
	}))).Methods("GET")
	router.Handle("/v0/markets/resolved", securityMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		q := r.URL.Query()
		q.Set("status", "resolved")
		r.URL.RawQuery = q.Encode()
		marketsHandler.ListMarkets(w, r)
	}))).Methods("GET")
	router.Handle("/v0/marketprojection/{marketId}/{amount}/{outcome}", securityMiddleware(marketshandlers.ProjectNewProbabilityHandler(marketsService))).Methods("GET")
	router.Handle("/v0/marketprojection/{marketId}/{amount}/{outcome}/", securityMiddleware(marketshandlers.ProjectNewProbabilityHandler(marketsService))).Methods("GET")

	// handle market positions, get trades - using service injection from new locations
	router.Handle("/v0/markets/bets/{marketId}", securityMiddleware(betshandlers.MarketBetsHandlerWithService(marketsService))).Methods("GET")
	router.Handle("/v0/markets/positions/{marketId}", securityMiddleware(positionshandlers.MarketPositionsHandlerWithService(marketsService))).Methods("GET")
	router.Handle("/v0/markets/positions/{marketId}/{username}", securityMiddleware(positionshandlers.MarketUserPositionHandlerWithService(marketsService))).Methods("GET")

	// handle public user stuff
	router.Handle("/v0/userinfo/{username}", securityMiddleware(usershandlers.GetPublicUserHandler(usersService))).Methods("GET")
	router.Handle("/v0/usercredit/{username}", securityMiddleware(usercredit.GetUserCreditHandler(usersService, econConfig.Economics.User.MaximumDebtAllowed))).Methods("GET")
	router.Handle("/v0/portfolio/{username}", securityMiddleware(publicuser.GetPortfolioHandler(usersService))).Methods("GET")
	router.Handle("/v0/users/{username}/financial", securityMiddleware(usershandlers.GetUserFinancialHandler(usersService))).Methods("GET")

	// handle private user stuff, display sensitive profile information to customize
	router.Handle("/v0/privateprofile", securityMiddleware(privateuser.GetPrivateProfileHandler(usersService))).Methods("GET")

	// changing profile stuff - apply security middleware
	router.Handle("/v0/changepassword", securityMiddleware(usershandlers.ChangePasswordHandler(usersService))).Methods("POST")
	router.Handle("/v0/profilechange/displayname", securityMiddleware(usershandlers.ChangeDisplayNameHandler(usersService))).Methods("POST")
	router.Handle("/v0/profilechange/emoji", securityMiddleware(usershandlers.ChangeEmojiHandler(usersService))).Methods("POST")
	router.Handle("/v0/profilechange/description", securityMiddleware(usershandlers.ChangeDescriptionHandler(usersService))).Methods("POST")
	router.Handle("/v0/profilechange/links", securityMiddleware(usershandlers.ChangePersonalLinksHandler(usersService))).Methods("POST")

	// handle private user actions such as make a bet, sell positions, get user position
	router.Handle("/v0/bet", securityMiddleware(buybetshandlers.PlaceBetHandler(container.GetBetsService(), container.GetUsersService()))).Methods("POST")
	router.Handle("/v0/userposition/{marketId}", securityMiddleware(usershandlers.UserMarketPositionHandlerWithService(marketsService, usersService))).Methods("GET")
	router.Handle("/v0/sell", securityMiddleware(sellbetshandlers.SellPositionHandler(container.GetBetsService(), container.GetUsersService()))).Methods("POST")

	// admin stuff - apply security middleware
	router.Handle("/v0/admin/createuser", securityMiddleware(http.HandlerFunc(adminhandlers.AddUserHandler(db, container.GetConfigService(), authService)))).Methods("POST")

	// homepage content routes
	homepageRepo := homepage.NewGormRepository(db)
	homepageRenderer := homepage.NewDefaultRenderer()
	homepageSvc := homepage.NewService(homepageRepo, homepageRenderer)
	homepageHandler := cmshomehttp.NewHandler(homepageSvc, authService)

	router.HandleFunc("/v0/content/home", homepageHandler.PublicGet).Methods("GET")
	router.Handle("/v0/admin/content/home", securityMiddleware(http.HandlerFunc(homepageHandler.AdminUpdate))).Methods("PUT")

	// Apply CORS middleware if enabled
	handler := http.Handler(router)
	if c != nil {
		handler = c.Handler(handler)
	}

	// Allow BACKEND_PORT to be configured via environment, default to 8080
	port := os.Getenv("BACKEND_PORT")
	if port == "" {
		port = "8080"
	}

	log.Printf("Starting server on :%s", port)
	if err := http.ListenAndServe(":"+port, handler); err != nil {
		log.Fatal(err)
	}
}

package setup

import (
	"encoding/json"
	"net/http"

	configsvc "socialpredict/internal/service/config"
)

func GetSetupHandler(configService configsvc.Service) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if configService == nil {
			http.Error(w, "Failed to load economic config", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		err := json.NewEncoder(w).Encode(configService.Economics())
		if err != nil {
			http.Error(w, "Failed to encode response", http.StatusInternalServerError)
		}
	}
}

type frontendChartsResponse struct {
	SigFigs int `json:"sigFigs"`
}

type frontendConfigResponse struct {
	Charts frontendChartsResponse `json:"charts"`
}

func GetFrontendSetupHandler(configService configsvc.Service) func(w http.ResponseWriter, r *http.Request) {
	return func(w http.ResponseWriter, r *http.Request) {
		if configService == nil {
			http.Error(w, "Failed to load frontend config", http.StatusInternalServerError)
			return
		}

		response := frontendConfigResponse{
			Charts: frontendChartsResponse{
				SigFigs: configService.ChartSigFigs(),
			},
		}

		w.Header().Set("Content-Type", "application/json")
		if err := json.NewEncoder(w).Encode(response); err != nil {
			http.Error(w, "Failed to encode frontend setup response", http.StatusInternalServerError)
			return
		}
	}
}

package statshandlers

import (
	"encoding/json"
	"net/http"
	configsvc "socialpredict/internal/service/config"
	"socialpredict/models"

	"gorm.io/gorm"
)

type FinancialStats struct {
	TotalMoney              int64 `json:"totalMoney"`
	TotalDebtExtended       int64 `json:"totalDebtExtended"`
	TotalDebtUtilized       int64 `json:"totalDebtUtilized"`
	TotalFeesCollected      int64 `json:"totalFeesCollected"`
	TotalBonusesPaid        int64 `json:"totalBonusesPaid"`
	OutstandingPayouts      int64 `json:"outstandingPayouts"`
	TotalMoneyInCirculation int64 `json:"totalMoneyInCirculation"` // Money currently active in bets
}

type SetupConfiguration struct {
	InitialMarketProbability   float64 `json:"initialMarketProbability"`
	InitialMarketSubsidization int64   `json:"initialMarketSubsidization"`
	InitialMarketYes           int64   `json:"initialMarketYes"`
	InitialMarketNo            int64   `json:"initialMarketNo"`
	CreateMarketCost           int64   `json:"createMarketCost"`
	TraderBonus                int64   `json:"traderBonus"`
	InitialAccountBalance      int64   `json:"initialAccountBalance"`
	MaximumDebtAllowed         int64   `json:"maximumDebtAllowed"`
	MinimumBet                 int64   `json:"minimumBet"`
	MaxDustPerSale             int64   `json:"maxDustPerSale"`
	InitialBetFee              int64   `json:"initialBetFee"`
	BuySharesFee               int64   `json:"buySharesFee"`
	SellSharesFee              int64   `json:"sellSharesFee"`
}

type StatsResponse struct {
	FinancialStats     FinancialStats     `json:"financialStats"`
	SetupConfiguration SetupConfiguration `json:"setupConfiguration"`
}

// StatsHandler handles requests for both financial stats and setup configuration.
func StatsHandler(db *gorm.DB, configService configsvc.Service) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if db == nil {
			http.Error(w, "Failed to calculate financial stats: database connection is not initialized", http.StatusInternalServerError)
			return
		}
		if configService == nil {
			http.Error(w, "Failed to load setup configuration: configuration service unavailable", http.StatusInternalServerError)
			return
		}

		// Calculate financial stats
		financialStats, err := calculateFinancialStats(db, configService)
		if err != nil {
			http.Error(w, "Failed to calculate financial stats: "+err.Error(), http.StatusInternalServerError)
			return
		}

		// Load setup configuration
		setupConfig := loadSetupConfiguration(configService.Current())

		response := StatsResponse{
			FinancialStats:     financialStats,
			SetupConfiguration: setupConfig,
		}

		w.Header().Set("Content-Type", "application/json")
		if err := json.NewEncoder(w).Encode(response); err != nil {
			http.Error(w, "Failed to encode stats response: "+err.Error(), http.StatusInternalServerError)
		}
	}
}

func calculateFinancialStats(db *gorm.DB, configService configsvc.Service) (FinancialStats, error) {
	var result FinancialStats

	// Calculate TotalMoney by calling the new function
	totalMoney, err := calculateTotalMoney(db, configService.Current())
	if err != nil {
		return result, err // Return the current result and the error
	}
	result.TotalMoney = totalMoney

	// Initialize other financial stats with dummy data (or implement real calculations)
	result.TotalDebtExtended = 0       // Real calculation should be implemented later
	result.TotalDebtUtilized = 0       // Real calculation should be implemented later
	result.TotalFeesCollected = 0      // Real calculation should be implemented later
	result.TotalBonusesPaid = 0        // Real calculation should be implemented later
	result.OutstandingPayouts = 0      // Real calculation should be implemented later
	result.TotalMoneyInCirculation = 0 // Real calculation should be implemented later

	return result, nil
}

// calculateTotalMoney calculates the total initial money in the system based on the number of regular users.
func calculateTotalMoney(db *gorm.DB, economicConfig *configsvc.AppConfig) (int64, error) {
	// Count the number of regular users
	var userCount int64
	if err := db.Model(&models.User{}).Where("user_type = ?", "REGULAR").Count(&userCount).Error; err != nil {
		return 0, err // Return zero and the error if the query fails
	}

	// Calculate total money based on the initial account balance and user count
	totalMoney := economicConfig.Economics.User.InitialAccountBalance * userCount
	return totalMoney, nil
}

// loadSetupConfiguration loads the setup configuration from setup.yaml
func loadSetupConfiguration(economicConfig *configsvc.AppConfig) SetupConfiguration {
	var result SetupConfiguration

	// Map configuration values to our response struct
	result.InitialMarketProbability = economicConfig.Economics.MarketCreation.InitialMarketProbability
	result.InitialMarketSubsidization = economicConfig.Economics.MarketCreation.InitialMarketSubsidization
	result.InitialMarketYes = economicConfig.Economics.MarketCreation.InitialMarketYes
	result.InitialMarketNo = economicConfig.Economics.MarketCreation.InitialMarketNo
	result.CreateMarketCost = economicConfig.Economics.MarketIncentives.CreateMarketCost
	result.TraderBonus = economicConfig.Economics.MarketIncentives.TraderBonus
	result.InitialAccountBalance = economicConfig.Economics.User.InitialAccountBalance
	result.MaximumDebtAllowed = economicConfig.Economics.User.MaximumDebtAllowed
	result.MinimumBet = economicConfig.Economics.Betting.MinimumBet
	result.MaxDustPerSale = economicConfig.Economics.Betting.MaxDustPerSale
	result.InitialBetFee = economicConfig.Economics.Betting.BetFees.InitialBetFee
	result.BuySharesFee = economicConfig.Economics.Betting.BetFees.BuySharesFee
	result.SellSharesFee = economicConfig.Economics.Betting.BetFees.SellSharesFee

	return result
