func EnsureDBReady(db *gorm.DB, maxAttempts int) error {
	var err error
	for attempts := 1; attempts <= maxAttempts; attempts++ {
		// Attempt to perform a simple operation like pinging the database
		sqlDB, err := db.DB()
		if err != nil {
			log.Printf("Unable to get database/sql DB from GORM DB: %v", err)
			time.Sleep(time.Second * 5)
			continue
		}

		err = sqlDB.Ping()
		if err != nil {
			log.Printf("Failed to connect to the database, attempt %d/%d: %v", attempts, maxAttempts, err)
			time.Sleep(time.Second * 5) // Wait before retrying
			continue
		}

		log.Println("Database is ready.")
		return nil
	}

	return fmt.Errorf("database is not ready after %d attempts: %v", maxAttempts, err)
}

func SeedHomepage(db *gorm.DB, repoRoot string) error {
	var count int64
	if err := db.Model(&models.HomepageContent{}).
		Where("slug = ?", "home").Count(&count).Error; err != nil {
		return err
	}
	if count > 0 {
		return nil
	}

	// Use embedded content to avoid filesystem path issues
	var data []byte
	if len(defaultHomeMD) > 0 {
		data = defaultHomeMD
	} else {
		// Fallback only if embedding failed
		data = []byte("# Welcome to BrierFoxForecast\n\nThis is the seeded home page.")
	}

	// Create renderer for sanitization
	renderer := homepage.NewDefaultRenderer()

	// Since the content is pure HTML, treat it as HTML format
	htmlContent := string(data)

	// Sanitize the HTML directly (no markdown conversion needed)
	sanitizedHTML := renderer.SanitizeHTML(htmlContent)

	item := models.HomepageContent{
		Slug:     "home",
		Title:    "Home",
		Format:   "html", // Changed to html since content is pure HTML
		Markdown: "",     // Empty since we're using HTML format
		HTML:     sanitizedHTML,
		Version:  1,
	}

	return db.Create(&item).Error
}

package config

import "socialpredict/setup"

const (
	minChartSigFigs     = 2
	maxChartSigFigs     = 9
	defaultChartSigFigs = 4
)

type AppConfig = setup.EconomicConfig
type Economics = setup.Economics
type Frontend = setup.Frontend

// Service exposes typed access to application configuration slices.
type Service interface {
	Current() *AppConfig
	Economics() Economics
	Frontend() Frontend
	ChartSigFigs() int
}

// Loader loads configuration from its source of truth.
type Loader interface {
	Load() (*AppConfig, error)
}

type LoaderFunc func() (*AppConfig, error)

func (f LoaderFunc) Load() (*AppConfig, error) {
	return f()
}

type RuntimeService struct {
	current *AppConfig
}

func NewService(loader Loader) (*RuntimeService, error) {
	if loader == nil {
		return NewStaticService(nil), nil
	}

	cfg, err := loader.Load()
	if err != nil {
		return nil, err
	}

	return NewStaticService(cfg), nil
}

func NewStaticService(cfg *AppConfig) *RuntimeService {
	if cfg == nil {
		cfg = &AppConfig{}
	}

	return &RuntimeService{current: cfg}
}

func (s *RuntimeService) Current() *AppConfig {
	if s == nil || s.current == nil {
		return &AppConfig{}
	}
	return s.current
}

func (s *RuntimeService) Economics() Economics {
	return s.Current().Economics
}

func (s *RuntimeService) Frontend() Frontend {
	return s.Current().Frontend
}

func (s *RuntimeService) ChartSigFigs() int {
	return ClampChartSigFigs(s.Frontend())
}

func ClampChartSigFigs(frontend Frontend) int {
	sigFigs := frontend.Charts.SigFigs
	if sigFigs == 0 {
		sigFigs = defaultChartSigFigs
	}

	if sigFigs < minChartSigFigs {
		return minChartSigFigs
	}
	if sigFigs > maxChartSigFigs {
		return maxChartSigFigs
	}
	return sigFigs
}

